SELECT * FROM customer c, customer_address ca, customer_demographics, store_sales, date_dim, web_sales, catalog_sales WHERE c.c_current_addr_sk = ca.ca_address_sk AND cd_demo_sk = c.c_current_cdemo_sk AND c.c_customer_sk = ss_customer_sk AND ss_sold_date_sk = d_date_sk AND d_year = 1999 AND c.c_customer_sk = ws_bill_customer_sk AND ws_sold_date_sk = d_date_sk AND c.c_customer_sk = cs_ship_customer_sk AND cs_sold_date_sk = d_date_sk;
